// Lista conversas com agente-off respeitando min_age_hours.
// Suporta dry_run: se true, NAO repassa para o node Remover; so retorna a lista.
const body = $('Webhook Cleanup').first().json.body || {};
const minAgeHours = Number(body.min_age_hours ?? 1);
const dryRun = body.dry_run === true || body.dry_run === 'true';
const MIN_MS = minAgeHours * 60 * 60 * 1000;
const now = Date.now();
const out = [];

for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  const resp = item.json;
  const conversations = resp?.data?.payload || resp?.payload || [];
  const tenant = $('Tenants Ativos').itemMatching(i)?.json || {};
  for (const conv of conversations) {
    const labels = conv.labels || conv.meta?.labels || [];
    if (!labels.includes('agente-off')) continue;
    if (labels.includes('aguardando_reagendamento')) continue;
    const lastTs = conv.last_activity_at || conv.timestamp || 0;
    const ageMs = now - (lastTs * 1000);
    if (ageMs < MIN_MS) continue;
    out.push({
      json: {
        conv_id: conv.id,
        contact_name: conv.meta?.sender?.name || 'Paciente',
        contact_phone: conv.meta?.sender?.phone_number || null,
        labels_atuais: labels,
        labels_novas: labels.filter(l => l !== 'agente-off'),
        age_hours: Math.round(ageMs / 1000 / 60 / 60),
        tenant_id: tenant.tenant_id,
        clinic_name: tenant.clinic_name,
        chatwoot_url: tenant.chatwoot_url,
        chatwoot_account_id: tenant.chatwoot_account_id,
        dry_run: dryRun,
      },
    });
  }
}
// Se dry_run, vazia o array pra que o node Remover nao execute
// e o sumario reflita a lista que SERIA modificada
if (dryRun) {
  // ainda retorna pra o code Sumario via paired-item (Sumario le de Filtrar por min_age.all())
  return [];
}
return out;

// Sumario funciona tanto pra dry_run quanto pra execucao real.
// Em dry_run, Filtrar por min_age retorna [] (nao chama Remover) mas conserva
// os items consultaveis via $('Filtrar por min_age').all() ... mas como o node
// retornou [], all() tb fica vazio. Fallback: refazer query.

// Pra dry_run funcionar, vou armazenar a lista no body do webhook output
const removed = $input.all();
const body = $('Webhook Cleanup').first().json.body || {};
const dryRun = body.dry_run === true || body.dry_run === 'true';

if (dryRun) {
  // Re-roda a logica de filtragem inline pra retornar a lista que SERIA modificada
  const minAgeHours = Number(body.min_age_hours ?? 1);
  const MIN_MS = minAgeHours * 60 * 60 * 1000;
  const now = Date.now();
  const allConvs = $('Listar conversas off').all();
  const tenants = $('Tenants Ativos').all();
  const list = [];
  for (let i = 0; i < allConvs.length; i++) {
    const conversations = allConvs[i].json?.data?.payload || allConvs[i].json?.payload || [];
    const tenant = tenants[i]?.json || {};
    for (const conv of conversations) {
      const labels = conv.labels || conv.meta?.labels || [];
      if (!labels.includes('agente-off')) continue;
      if (labels.includes('aguardando_reagendamento')) continue;
      const lastTs = conv.last_activity_at || conv.timestamp || 0;
      const ageMs = now - (lastTs * 1000);
      if (ageMs < MIN_MS) continue;
      list.push({
        conv_id: conv.id,
        age_hours: Math.round(ageMs / 1000 / 60 / 60),
        contact_name: conv.meta?.sender?.name || 'Paciente',
        tenant_id: tenant.tenant_id,
      });
    }
  }
  list.sort((a, b) => b.age_hours - a.age_hours);
  return [{ json: { success: true, dry_run: true, would_clean: list.length, min_age_hours: minAgeHours, conversations: list } }];
}

const rows = removed.map(i => ({ conv_id: i.json.conv_id, age_hours: i.json.age_hours, contact_name: i.json.contact_name, tenant_id: i.json.tenant_id }));
rows.sort((a, b) => b.age_hours - a.age_hours);
return [{ json: { success: true, dry_run: false, total_cleaned: rows.length, conversations: rows } }];
